import React, { useMemo } from 'react';
import { useIntl } from 'gatsby-plugin-intl';
import { makeStyles } from '@material-ui/core/styles';
import { Typography } from '@material-ui/core';
import { graphql } from 'gatsby';
import BackgroundImage from 'gatsby-background-image';

// Utils
import { getAlternateLangLinks } from '../utils/gatsby-frontend-helpers';

// Components
import SEO from '../components/SEO';
import Countdown from '../components/Countdown';
import Layout from '../components/Layout';
import FloatingControls from '../components/FloatingControls';

const useStyles = makeStyles((theme) => ({
    imageWrapper: {
        backgroundRepeat: 'no-repeat !important',
        backgroundSize: 'cover !important',
        width: '100% !important',
        height: '100vh !important',
        display: 'inline-block !important',
    },
    countdownLeadingText: {
        textAlign: 'center',
        marginTop: '50px',
        textShadow: `2px 2px 13px ${theme.palette.background.default}`,
    },
    countdownText: {
        color: theme.palette.text.primary,
        backgroundColor: `${theme.palette.background.default}db`,
    },
}));

const GamescomCountdown = ({ location, data, pageContext }) => {
    const intl = useIntl();
    const { gamescomBackgroundImage } = data;
    const classes = useStyles();
    const alternateLangLinks = useMemo(
        () => getAlternateLangLinks(pageContext, data.site.siteMetadata.siteUrl),
        [data.site.siteMetadata.siteUrl, pageContext]
    );

    return (
        <Layout hideTopbar>
            <SEO
                lang={intl.locale}
                pathname={location?.pathname}
                title={intl.formatMessage({ id: 'gamescom_countdown' })}
                ogImage={gamescomBackgroundImage.childImageSharp.fluid.src}
                keywords={[
                    intl.formatMessage({ id: 'seo_keywords.games' }),
                    intl.formatMessage({ id: 'seo_keywords.gamescom' }),
                    intl.formatMessage({ id: 'seo_keywords.countdown' }),
                ]}
                alternateLangLinks={alternateLangLinks}
            />
            <BackgroundImage
                className={classes.imageWrapper}
                Tag="section"
                fluid={gamescomBackgroundImage.childImageSharp.fluid}
            >
                <FloatingControls />
                <Typography
                    className={classes.countdownLeadingText}
                    variant="h4"
                    color="textPrimary"
                >
                    {intl.formatMessage({ id: 'we_are' })}
                </Typography>
                <Countdown
                    date="2021-08-25T00:00:00"
                    showYear={false}
                    className={classes.countdownText}
                />
                <Typography
                    className={classes.countdownLeadingText}
                    variant="h4"
                    color="textPrimary"
                >
                    {intl.formatMessage({ id: 'away_from_next_gamescom' })}
                </Typography>
            </BackgroundImage>
        </Layout>
    );
};

export default GamescomCountdown;

export const pageQuery = graphql`
    query {
        gamescomBackgroundImage: file(absolutePath: { regex: "/gamescom-countdown-bg.jpg/" }) {
            childImageSharp {
                fluid(maxWidth: 1200) {
                    ...GatsbyImageSharpFluid_tracedSVG
                }
            }
        }
        site {
            siteMetadata {
                siteUrl
            }
        }
    }
`;
